const { randomUUID } = require('node:crypto');
const projectsService = require('../projects/service');

let tasksStore = [];

async function addTask(projectId, task) {
  const project = await projectsService.getProjectById(projectId);
  if (!project) return null;

  const newTask = { id: randomUUID(), projectId, status: 'todo', ...task };
  tasksStore.push(newTask);
  return newTask;
}

async function getTasks(projectId) {
  const project = await projectsService.getProjectById(projectId);
  if (!project) return [];

  return tasksStore.filter(task => task.projectId === projectId);
}

async function updateTaskStatus(projectId, taskId, status) {
  const taskIndex = tasksStore.findIndex(task => task.id === taskId && task.projectId === projectId);
  if (taskIndex === -1) return null;

  tasksStore[taskIndex].status = status;
  return tasksStore[taskIndex];
}

module.exports = {
  addTask,
  getTasks,
  updateTaskStatus,
};
